"use strict";const t=require("../utils/request.js");exports.createGoods=function(e){return t.request({url:"/goods",method:"POST",data:e})},exports.getGoods=function(e){return t.request({url:"/goods",method:"GET",data:e})},exports.getGoodsDetail=function(e){return t.request({url:`/goods/${e}`,method:"GET"})},exports.getMyGoods=function(e){return t.request({url:"/goods/my/list",method:"GET",data:e})},exports.uploadImage=async function(e){return(await t.uploadFile("/goods/upload",e,"file")).url};
